  `rate_type` enum('hourly','daily','monthly','annual') DEFAULT 'monthly',
  `rate_amount` decimal(12,2) DEFAULT 0.00,
  `status` enum('active','inactive','on_leave','terminated') NOT NULL DEFAULT 'active',
