--
-- Table structure for table `leads`
--

DROP TABLE IF EXISTS `leads`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `leads` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `company_id` int(10) unsigned DEFAULT NULL,
  `stage` varchar(80) NOT NULL DEFAULT 'new',
  `customer_name` varchar(150) NOT NULL,
  `email` varchar(255) NOT NULL,
  `phone` varchar(50) NOT NULL,
  `suburb` varchar(150) DEFAULT NULL,
  `system_size_kw` decimal(10,2) DEFAULT NULL,
  `pv_system_size_kw` decimal(10,2) DEFAULT NULL,
  `pv_inverter_size_kw` decimal(10,2) DEFAULT NULL,
  `pv_inverter_brand` varchar(120) DEFAULT NULL,
  `pv_panel_brand` varchar(120) DEFAULT NULL,
  `pv_panel_module_watts` int(11) DEFAULT NULL,
  `ev_charger_brand` varchar(120) DEFAULT NULL,
  `ev_charger_model` varchar(120) DEFAULT NULL,
  `battery_size_kwh` decimal(10,2) DEFAULT NULL,
  `battery_brand` varchar(120) DEFAULT NULL,
  `battery_model` varchar(120) DEFAULT NULL,
  `value_amount` decimal(14,2) DEFAULT NULL,
  `source` varchar(100) DEFAULT NULL,
  `referred_by_lead_id` bigint(20) unsigned DEFAULT NULL,
  `is_closed` tinyint(1) NOT NULL DEFAULT 0,
  `is_won` tinyint(1) NOT NULL DEFAULT 0,
  `won_lost_at` datetime DEFAULT NULL,
  `last_activity_at` datetime DEFAULT NULL,
  `site_inspection_date` datetime DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT NULL ON UPDATE current_timestamp(),
  `system_type` varchar(100) DEFAULT NULL,
  `house_storey` varchar(50) DEFAULT NULL,
  `roof_type` varchar(100) DEFAULT NULL,
  `meter_phase` varchar(20) DEFAULT NULL,
  `access_to_second_storey` tinyint(1) DEFAULT NULL,
  `access_to_inverter` tinyint(1) DEFAULT NULL,
  `pre_approval_reference_no` varchar(100) DEFAULT NULL,
  `energy_retailer` varchar(120) DEFAULT NULL,
  `energy_distributor` varchar(120) DEFAULT NULL,
  `solar_vic_eligibility` tinyint(1) DEFAULT NULL,
  `nmi_number` varchar(50) DEFAULT NULL,
  `meter_number` varchar(50) DEFAULT NULL,
  `contacted_at` datetime DEFAULT NULL,
  `last_inbound_email_at` datetime DEFAULT NULL,
  `last_outbound_email_at` datetime DEFAULT NULL,
  `followup_first_sent_at` datetime DEFAULT NULL,
  `followup_second_sent_at` datetime DEFAULT NULL,
  `flagged_for_review_at` datetime DEFAULT NULL,
  `auto_close_nonresponsive` tinyint(1) NOT NULL DEFAULT 0,
  `lost_reason` varchar(120) DEFAULT NULL,
  `owner_doc_last_sent_at` datetime DEFAULT NULL,
  `owner_doc_reminders_count` int(11) NOT NULL DEFAULT 0,
  `external_id` varchar(255) DEFAULT NULL,
  `marketing_payload_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`marketing_payload_json`)),
  `sales_segment` varchar(8) DEFAULT NULL COMMENT 'b2c | b2b',
  `assigned_user_id` int(10) unsigned DEFAULT NULL,
  `customer_portal_pre_approval_announced` tinyint(1) NOT NULL DEFAULT 0,
  `customer_portal_solar_vic_announced` tinyint(1) NOT NULL DEFAULT 0,
  `pv_panel_model` varchar(120) DEFAULT NULL,
  `pv_panel_quantity` int(11) DEFAULT NULL,
  `pv_inverter_model` varchar(120) DEFAULT NULL,
  `pv_inverter_series` varchar(120) DEFAULT NULL,
  `pv_inverter_power_kw` decimal(10,2) DEFAULT NULL,
  `pv_inverter_quantity` int(11) DEFAULT NULL,
  `pylon_solar_project_id` varchar(32) DEFAULT NULL,
  `pylon_proposal_url` varchar(768) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_leads_board` (`stage`,`updated_at`),
  KEY `idx_leads_stage_count` (`stage`),
  KEY `idx_leads_value` (`value_amount`),
  KEY `idx_leads_text` (`customer_name`),
  KEY `idx_leads_suburb` (`suburb`),
  KEY `idx_leads_site_inspection_date` (`site_inspection_date`),
  KEY `idx_leads_external_id` (`external_id`),
  KEY `idx_leads_referred_by` (`referred_by_lead_id`),
  KEY `idx_leads_company` (`company_id`),
  KEY `idx_leads_assigned` (`assigned_user_id`),
  CONSTRAINT `fk_leads_assigned` FOREIGN KEY (`assigned_user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_leads_company` FOREIGN KEY (`company_id`) REFERENCES `companies` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=139 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

